import{_ as o}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{c,o as d,X as t}from"./chunks/vendor-vueuse.XPft87tp.js";const b=JSON.parse('{"title":"原生对象、内置对象、宿主对象，傻傻分不清","description":"","frontmatter":{},"headers":[],"relativePath":"basics/object-types.md","filePath":"basics/object-types.md","lastUpdated":1784884957000}'),a={name:"basics/object-types.md"};function r(i,e,l,s,n,p){return d(),c("div",null,e[0]||(e[0]=[t('<h1 id="原生对象、内置对象、宿主对象-傻傻分不清" tabindex="-1">原生对象、内置对象、宿主对象，傻傻分不清 <a class="header-anchor" href="#原生对象、内置对象、宿主对象-傻傻分不清" aria-label="Permalink to &quot;原生对象、内置对象、宿主对象，傻傻分不清&quot;">​</a></h1><p>这三个概念经常被混着用，但它们确实不一样。一句话区分：</p><ul><li><strong>原生对象</strong>：ECMAScript 规范定义的，比如 <code>Object</code>、<code>Array</code>、<code>Function</code>、<code>Date</code>、<code>RegExp</code></li><li><strong>内置对象</strong>：原生对象里&quot;不用 new 就能用&quot;的那部分，比如 <code>Math</code>、<code>JSON</code>、<code>globalThis</code></li><li><strong>宿主对象</strong>：运行环境提供的，比如浏览器里的 <code>window</code>、<code>document</code>、<code>console</code>，Node.js 里的 <code>process</code>、<code>Buffer</code></li></ul><h2 id="原生对象" tabindex="-1">原生对象 <a class="header-anchor" href="#原生对象" aria-label="Permalink to &quot;原生对象&quot;">​</a></h2><p>JS 语言本身带的。按规范，原生对象又分两类：</p><p><strong>构造器类</strong>（可以用 <code>new</code> 创建实例）： <code>Object</code>、<code>Array</code>、<code>Function</code>、<code>Date</code>、<code>RegExp</code>、<code>String</code>、<code>Number</code>、<code>Boolean</code>、<code>Error</code>、<code>Map</code>、<code>Set</code>、<code>Promise</code>……</p><p><strong>非构造器类</strong>（直接用，不能 <code>new</code>）： <code>Math</code>、<code>JSON</code>、<code>Reflect</code>、<code>Proxy</code>（好吧 Proxy 确实用 <code>new</code>）……</p><h2 id="内置对象" tabindex="-1">内置对象 <a class="header-anchor" href="#内置对象" aria-label="Permalink to &quot;内置对象&quot;">​</a></h2><p>ECMAScript 规范里把&quot;不需要显式实例化、全局就能访问的&quot;叫内置对象。<code>Math</code> 和 <code>JSON</code> 是两个典型——不需要 <code>new Math()</code>，直接用。</p><p><code>globalThis</code> 也算。在浏览器里它是 <code>window</code>，在 Node.js 里它是 <code>global</code>，在 Worker 里它是 <code>self</code>。ES2020 统一成了 <code>globalThis</code>。</p><h2 id="宿主对象" tabindex="-1">宿主对象 <a class="header-anchor" href="#宿主对象" aria-label="Permalink to &quot;宿主对象&quot;">​</a></h2><p>这取决于运行环境。浏览器的宿主对象就是 Web API 那套东西：</p><ul><li>DOM：<code>document</code>、<code>HTMLElement</code>、<code>NodeList</code></li><li>BOM：<code>window</code>、<code>location</code>、<code>history</code>、<code>navigator</code></li><li>其他：<code>console</code>、<code>fetch</code>、<code>localStorage</code>、<code>setTimeout</code></li></ul><p>Node.js 的宿主对象是另一套：</p><ul><li><code>process</code>、<code>Buffer</code>、<code>require</code>、<code>__dirname</code>、<code>__filename</code></li><li><code>fs</code>、<code>http</code> 等模块提供的对象</li></ul><p>注意 <code>console</code> 和 <code>setTimeout</code> 在 Node 和浏览器里都有，但它们是各自环境的宿主对象，实现细节不同。</p><h2 id="为什么要分清楚" tabindex="-1">为什么要分清楚 <a class="header-anchor" href="#为什么要分清楚" aria-label="Permalink to &quot;为什么要分清楚&quot;">​</a></h2><p>实际开发中你不会天天纠结这些分类。但理解它们有几个实际意义：</p><ul><li>做兼容性时知道哪些是 ECMAScript 标准（到处都有）、哪些是宿主环境特有的（IE 可能没有）</li><li>写同构代码（SSR、跨端）时能判断哪些 API 在 Node 和浏览器里行为不同</li><li>面试被问到能说清楚，不被概念绕晕</li></ul>',19)]))}const m=o(a,[["render",r]]);export{b as __pageData,m as default};
